public class Solution {

    private static boolean util(long[][] arr, long mid) {
        int n = arr.length;
        long count = 0;
        for(long[] val : arr) {
            long low = val[0];
            long high = val[1];

            if(high >= mid-1 && mid-1 >= low) count++;
        }
        return count >= mid;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        int n = scanner.nextInt();
        long[][] arr = new long[n][2];
        long low = 0;
        long high = n;
        for(int i=0; i<n; i++) {
            long v1 = scanner.nextInt();
            long v2 = scanner.nextInt();
            arr[i][0] = v1;
            arr[i][1] = v2;
            high = Math.max(high, v2);
        }
        high = Integer.MAX_VALUE;
        long ans = 0;
        while(low <= high) {
            long mid = low + (high - low)/2;
            boolean isPos = util(arr, mid);
            if(isPos) {
                ans = Math.max(ans, mid);
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        System.out.println(ans);
        return;
    }
}`

