   public static  int  findMaxPeople(int n, int min[],int max[]){
    int ans=0;
    PriorityQueue <Pair> pq=new PriorityQueue<>((a,b)->a.max-b.max);
    for(int i=0;i<n;i++){
        Pair p=new Pair(min[i]+1,max[i]+1);
        pq.add(p);
        if(pq.peek().max<pq.size()){
            pq.poll();
        }
        ans=Math.max(ans, pq.size());
    }
    return ans;
   }
}

